import { buildPortalView } from "./portal-view.mjs";

const CUSTOMER_STATUS = "Split-shipment exception active with replacement plan, owners, customer message, and audit trail.";

export function applyBenchmarkTask(db, now) {
  const request = db.workflow_requests[0];
  const account = db.accounts.find((item) => item._id === request.accountId);
  const activities = db.activities.filter((item) => item.subjectId === request._id);
  const ownerGroups = [...request.ownerGroups];
  const riskSignals = request.riskSignals.map((item) => ({ ...item }));
  const dueAt = addHours(now, 4);
  const timeline = activities.map((item) => ({ occurredAt: item.occurredAt, summary: item.summary }));

  upsertBy(db.workflow_state, (item) => item.requestId === request._id, {
    _id: request._id,
    requestId: request._id,
    accountId: account?._id ?? request.accountId,
    taskId: request.taskId,
    title: request.title,
    status: CUSTOMER_STATUS,
    nextStep: request.nextStep,
    ownerGroups,
    riskSignals,
    replacementPlan: {
      status: "active",
      partialFulfillment: "Split order is being completed in stages.",
      carrierDelay: "Replacement shipment is delayed in transit.",
      inventoryReservation: "Replacement inventory is reserved.",
      supportCase: "Support case remains open for enterprise follow-up."
    },
    reconciliation: {
      accountTier: account?.tier ?? "unknown",
      auditTimeline: timeline,
      activityCount: activities.length,
      lastActivityAt: activities.at(-1)?.occurredAt ?? now
    },
    customerMessage: request.customerMessage,
    updatedAt: now
  });

  ownerGroups.forEach((ownerGroup, index) => {
    upsertBy(
      db.owner_tasks,
      (item) => item.requestId === request._id && item.ownerGroup === ownerGroup,
      {
        _id: `task-${request._id}-${index + 1}`,
        requestId: request._id,
        accountId: account?._id ?? request.accountId,
        ownerGroup,
        taskType: "split-shipment-exception",
        title: `${ownerGroup} split-shipment action`,
        status: "open",
        dueAt,
        priority: account?.tier === "enterprise" ? "high" : "normal",
        summary: `${ownerGroup} to review partial fulfillment, carrier delay, inventory reservation, and audit timing.`
      }
    );
  });

  upsertBy(db.customer_messages, (item) => item.requestId === request._id, {
    _id: `msg-${request._id}`,
    requestId: request._id,
    accountId: account?._id ?? request.accountId,
    body: `${request.customerMessage} Replacement plan is active and the audit trail is recorded.`,
    customerVisible: true,
    createdAt: now
  });

  upsertBy(db.audit_events, (item) => item.requestId === request._id && item.kind === "split-shipment-exception-opened", {
    _id: `audit-${request._id}`,
    requestId: request._id,
    accountId: account?._id ?? request.accountId,
    kind: "split-shipment-exception-opened",
    customerVisible: true,
    occurredAt: now,
    status: CUSTOMER_STATUS,
    ownerGroups,
    riskSignals,
    timeline
  });

  return buildPortalView(db);
}

function upsertBy(collection, predicate, document) {
  const index = collection.findIndex(predicate);
  if (index === -1) {
    collection.push(document);
    return;
  }
  collection[index] = document;
}

function addHours(isoTimestamp, hours) {
  return new Date(Date.parse(isoTimestamp) + hours * 60 * 60 * 1000).toISOString();
}

